#include <stdio.h>
#include <string.h>
int main() {
    char s[100001];
    scanf("%s", s);
    int n = strlen(s), count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j <= n; j++) {
            int ok = 1;
            for (int k = 0; k < j - i - 1; k++) {
                if (s[i + k] == s[i + k + 1]) {
                    ok = 0;
                    break;
                }
            }
            if (ok) count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

